  })
});

function validateConfig(config) {
  const { error, value } = configSchema.validate(config, {
    abortEarly: false,
    stripUnknown: true
  });

  if (error) {
    const messages = error.details.map(d => d.message).join(', ');
    throw new Error(`Configuration validation failed: ${messages}`);
  }

  return value;
}

