```javascript
// Deduplication pattern using content hashing
const crypto = require('crypto');

function generateContentHash(content) {
    return crypto.createHash('sha256')
        .update(content.trim().toLowerCase())
        .digest('hex')
        .substring(0, 16);
}

async function insertWithDedup(db, entry) {
    const contentHash = generateContentHash(entry.content);
    const existingId = `hash_${contentHash}`;

    // Check if content already exists
    const existing = await db.get(existingId);

    if (existing) {
        // Update metadata, increment version
        const newVersion = (existing.metadata?.version || 1) + 1;
        await db.delete(existingId);
        entry.metadata.version = newVersion;
        entry.metadata.previousId = existingId;
    }

    entry.id = existingId;
    await db.insert(entry);
    return { id: existingId, deduplicated: !!existing };
}
