// Incremental update pattern
async function incrementalSync(sources, db) {
    const manifest = await loadManifest(db);
    const updates = [];

    for (const source of sources) {
        const stat = fs.statSync(source.path);
        const lastIngested = manifest.sources[source.path]?.lastIngested;

        if (!lastIngested || stat.mtime > new Date(lastIngested)) {
            updates.push({
                source,
                type: lastIngested ? 'update' : 'new',
                lastModified: stat.mtime
            });
        }
    }

    // Process only changed sources
    for (const update of updates) {
        await processFile(update.source.path, db);
        manifest.sources[update.source.path] = {
            lastIngested: new Date().toISOString(),
            hash: await computeFileHash(update.source.path)
        };
    }

    await saveManifest(db, manifest);
    return { processed: updates.length, total: sources.length };
}
