            uncoveredTopics.push({
                topic,
                coverage: topicCounts[topic] || 0,
                status: topicCounts[topic] ? 'sparse' : 'missing'
            });
        }
    }

    return {
        totalEntries: allEntries.length,
        topicDistribution: topicCounts,
        gaps: uncoveredTopics,
        coverageScore: 1 - (uncoveredTopics.length / expectedTopics.length)
    };
}
