// Consistency check pattern
async function verifyConsistency(db) {
    const issues = [];

    // Check for orphaned references
    const allEntries = await getAllEntries(db);
    const entryIds = new Set(allEntries.map(e => e.id));

    for (const entry of allEntries) {
        // Check internal references
        const refs = extractReferences(entry.metadata?.content || '');
        for (const ref of refs) {
            if (!entryIds.has(ref)) {
                issues.push({
                    type: 'orphaned_reference',
                    entry: entry.id,
                    missingRef: ref
                });
            }
        }

        // Check metadata completeness
        const requiredFields = ['source', 'timestamp', 'content'];
        for (const field of requiredFields) {
            if (!entry.metadata?.[field]) {
                issues.push({
                    type: 'missing_metadata',
                    entry: entry.id,
                    field
                });
            }
        }
    }

    return {
        valid: issues.length === 0,
        issues,
        score: 1 - (issues.length / (allEntries.length * 3))
    };
}
