knowledge-base-patterns.md_536.content:
Vector databases need a freshness layer to ensure data is queryable within seconds of insertion. For maintenance:

```javascript
// Freshness monitoring pattern
async function detectStaleness(db, maxAgeDays = 30) {
    const now = Date.now();
    const maxAge = maxAgeDays * 24 * 60 * 60 * 1000;
    const staleEntries = [];

    const allEntries = await getAllEntries(db);

    for (const entry of allEntries) {
        const timestamp = entry.metadata?.timestamp || entry.metadata?.ingestedAt;
        if (timestamp) {
            const age = now - new Date(timestamp).getTime();
            if (age > maxAge) {
                staleEntries.push({
                    id: entry.id,
                    age: Math.floor(age / (24 * 60 * 60 * 1000)),
                    source: entry.metadata?.source,
                    lastUpdated: timestamp
                });
            }
        }
    }

    return {
        total: allEntries.length,
        stale: staleEntries.length,
        freshnessScore: 1 - (staleEntries.length / allEntries.length),
        staleEntries
    };
}
```

