    const weights = {
        coverage: 0.25,
        consistency: 0.25,
        freshness: 0.20,
        accuracy: 0.30
    };

    const compositeScore =
        metrics.coverage.coverageScore * weights.coverage +
        metrics.consistency.score * weights.consistency +
        metrics.freshness.freshnessScore * weights.freshness +
        metrics.accuracy.accuracyScore * weights.accuracy;

    return {
        composite: compositeScore,
        breakdown: metrics,
        grade: compositeScore >= 0.9 ? 'A' :
               compositeScore >= 0.8 ? 'B' :
               compositeScore >= 0.7 ? 'C' :
               compositeScore >= 0.6 ? 'D' : 'F'
