// Query expansion pattern
async function expandQuery(query, context = {}) {
    const expansions = [];

    // 1. Synonym expansion
    const synonyms = getSynonyms(query);
    expansions.push(...synonyms);

    // 2. Context-aware expansion
    if (context.previousQuery) {
        expansions.push(context.previousQuery);
    }

    // 3. Pseudo Relevance Feedback (PRF)
    const initialResults = await db.search({ vector: await embed(query), k: 3 });
    for (const result of initialResults) {
        const keywords = extractKeywords(result.metadata?.content || '');
        expansions.push(...keywords.slice(0, 5));
    }

    // Combine original query with expansions
    const expandedQuery = [query, ...new Set(expansions)].join(' ');
    return expandedQuery;
}
