knowledge-base-patterns.md_739.content:
Feedback Loop RAG learns from user interactions to continuously improve retrieval quality:

```javascript
// Feedback loop pattern
class FeedbackLoopRAG {
    constructor(db) {
        this.db = db;
        this.feedbackStore = new Map();
        this.relevanceScores = new Map();
    }

    async search(query, k = 10) {
        const results = await this.db.search({
            vector: await generateEmbedding(query),
            k
        });

        // Apply learned relevance adjustments
        const adjustedResults = results.map(r => ({
            ...r,
            adjustedScore: r.score * (this.relevanceScores.get(r.id) || 1.0)
        }));

        return adjustedResults.sort((a, b) => b.adjustedScore - a.adjustedScore);
    }

    async recordFeedback(query, resultId, isRelevant) {
        // Store feedback for learning
        const key = `${query}_${resultId}`;
        this.feedbackStore.set(key, {
            query,
            resultId,
            isRelevant,
            timestamp: Date.now()
        });

        // Update relevance scores
        const currentScore = this.relevanceScores.get(resultId) || 1.0;
        const adjustment = isRelevant ? 1.1 : 0.9;
        this.relevanceScores.set(resultId, currentScore * adjustment);

        // If consistently helpful, add to knowledge base
        if (isRelevant) {
            await this.incorporateSuccessfulQA(query, resultId);
        }
    }

    async incorporateSuccessfulQA(query, answerId) {
        // Add successful Q&A pairs back to knowledge base
        const answer = await this.db.get(answerId);
        if (answer && this.getRelevanceCount(answerId) >= 3) {
            await this.db.insert({
                id: `qa_${Date.now()}`,
                vector: await generateEmbedding(`${query} ${answer.metadata?.content}`),
                metadata: {
                    type: 'qa_pair',
                    question: query,
                    answer: answer.metadata?.content,
                    sourceId: answerId,
                    learnedAt: new Date().toISOString()
                }
            });
        }
    }
