// A/B testing pattern for retrieval
class RetrievalExperiment {
    constructor(db, strategies) {
        this.db = db;
        this.strategies = strategies;
        this.results = new Map();
    }

    async search(query, experimentId = 'default') {
        // Randomly select strategy
        const strategyIndex = Math.floor(Math.random() * this.strategies.length);
        const strategy = this.strategies[strategyIndex];

        // Execute search with selected strategy
        const startTime = performance.now();
        const results = await strategy.search(this.db, query);
        const latency = performance.now() - startTime;

        // Log experiment data
        this.logExperiment(experimentId, {
            strategy: strategy.name,
            query,
            resultCount: results.length,
            topScore: results[0]?.score || 0,
            latency
        });

        return { results, strategy: strategy.name };
    }

    getAnalytics() {
        const analytics = {};
        for (const [strategyName, data] of this.results) {
            analytics[strategyName] = {
                avgLatency: mean(data.map(d => d.latency)),
                avgTopScore: mean(data.map(d => d.topScore)),
                queries: data.length
            };
        }
        return analytics;
    }
}
