```javascript
// Backup strategy pattern
class BackupManager {
    constructor(db, backupPath = '.ruvector/backups') {
        this.db = db;
        this.backupPath = backupPath;
    }

    async createBackup() {
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const backupDir = path.join(this.backupPath, `backup-${timestamp}`);

        await mkdir(backupDir, { recursive: true });

        // Copy current files
        const paths = this.db.getPaths();
        for (const [name, filePath] of Object.entries(paths)) {
            if (fs.existsSync(filePath)) {
                await copyFile(filePath, path.join(backupDir, path.basename(filePath)));
            }
        }

        // Create backup manifest
        await writeFile(path.join(backupDir, 'backup-manifest.json'), JSON.stringify({
            createdAt: new Date().toISOString(),
            vectorCount: this.db.vectorCache.size,
            stats: this.db.getStats()
        }, null, 2));

        return backupDir;
    }

    async restoreFromBackup(backupDir) {
        // Verify backup integrity
        const backupManifest = JSON.parse(
            await readFile(path.join(backupDir, 'backup-manifest.json'), 'utf8')
        );

        // Stop current operations
        await this.db.close();

        // Restore files
        const dbPath = this.db.options.path;
        const files = ['vectors.bin', 'metadata.json', 'manifest.json'];

        for (const file of files) {
            const src = path.join(backupDir, file);
            const dest = path.join(dbPath, file);
            if (fs.existsSync(src)) {
                await copyFile(src, dest);
            }
        }

        // Clear WAL (already incorporated in backup)
        const walPath = path.join(dbPath, 'wal.log');
        await writeFile(walPath, '');

        // Reinitialize
        await this.db.initialize();

        return backupManifest;
    }

    async listBackups() {
        const backups = [];
        const dirs = fs.readdirSync(this.backupPath);

        for (const dir of dirs) {
            if (dir.startsWith('backup-')) {
                const manifestPath = path.join(this.backupPath, dir, 'backup-manifest.json');
                if (fs.existsSync(manifestPath)) {
                    const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf8'));
                    backups.push({
                        name: dir,
                        path: path.join(this.backupPath, dir),
                        ...manifest
                    });
                }
            }
        }

        return backups.sort((a, b) =>
            new Date(b.createdAt) - new Date(a.createdAt)
        );
    }
}
