// Complete RAG flow with RuVector + RuvLLM
async function ragQuery(question, config) {
    // 1. Generate query embedding
    const queryEmbedding = await generateEmbedding(question, config.dimensions);

    // 2. Search knowledge base
    const searchResults = await db.search({
        vector: queryEmbedding,
        k: config.rag.topK
    });

    // 3. Filter by similarity threshold
    const relevantResults = searchResults.filter(
        r => r.score >= config.rag.minSimilarity
    );

    // 4. Build context from results
    const context = relevantResults
        .map(r => r.metadata?.content || '')
        .join('\n\n---\n\n');

    // 5. Apply prompt template
    const prompt = config.rag.promptTemplate
        .replace('{context}', context)
        .replace('{question}', question);

    // 6. Generate response with LLM
    const response = await llm.generate(prompt, {
        model: config.ollama.model,
        ...config.ollama.options
    });

    // 7. Return with citations
    return {
        answer: response,
        sources: relevantResults.map(r => ({
            id: r.id,
            score: r.score,
            source: r.metadata?.source,
            section: r.metadata?.section
        }))
    };
}
