}

impl FastGRNN {
    pub fn forward(&self, x: &[f32], h: &[f32]) -> Vec<f32> {
        // z = sigmoid(W_z * [x, h] + b_z)
        let z = self.compute_gate(x, h);

        // h_tilde = tanh(W_h * [x, h] + b_h)
        let h_tilde = self.compute_candidate(x, h);

        // h_new = (zeta * (1-z) + nu) * h + z * h_tilde
        self.combine_states(&z, h, &h_tilde)
    }

    pub fn route(&self, query_embedding: &[f32]) -> ModelSelection {
        let features = self.extract_routing_features(query_embedding);
        let scores = self.forward(&features, &self.hidden_state);

        ModelSelection::from_scores(&scores)
    }
}
```

**FastGRNN Advantages:**
- 10-100x smaller than standard GRU
- Sparse + low-rank decomposition
- Quantization-friendly
- <10μs routing latency

