guru_ruvllm-complete_454.content:
Low-Rank Adaptation enables efficient fine-tuning without full model updates:

#### MicroLoRA (Per-Request)
```rust
pub struct MicroLoRA {
    rank: usize,        // Typically 1-2
    alpha: f32,         // Scaling factor
    a: Matrix,          // Down projection: d -> r
    b: Matrix,          // Up projection: r -> d
    learning_rate: f32, // Very small: 1e-5
}

impl MicroLoRA {
    /// Apply LoRA delta to base weights
    pub fn forward(&self, x: &Tensor, base_output: &Tensor) -> Tensor {
        // delta = (x @ A) @ B * (alpha / rank)
        let delta = x.matmul(&self.a).matmul(&self.b);
        let scaled = delta * (self.alpha / self.rank as f32);

        base_output + scaled
    }

    /// Per-request adaptation
    pub fn adapt(&mut self, gradient: &Tensor, feedback: f32) {
        // Only update if feedback is significant
        if feedback.abs() > FEEDBACK_THRESHOLD {
            self.b.add_scaled(gradient, self.learning_rate * feedback);
        }
    }
}
```

#### BaseLoRA (Hourly Consolidation)
```rust
pub struct BaseLoRA {
    rank: usize,        // Typically 4-16
    modules: HashMap<String, LoRAModule>,
    merge_strategy: MergeStrategy,
}

impl BaseLoRA {
    /// Merge MicroLoRA updates into BaseLoRA
    pub fn merge_updates(&mut self, micro_updates: &[MicroLoRA]) {
        for (name, module) in &mut self.modules {
            let deltas: Vec<_> = micro_updates
                .iter()
                .filter_map(|u| u.get_delta(name))
                .collect();

            if !deltas.is_empty() {
                let merged = self.merge_strategy.merge(&deltas);
                module.integrate(merged);
            }
        }
    }
}
```

guru_ruvllm-complete_514.content:
EWC++ prevents catastrophic forgetting during continual learning:

```rust
pub struct EWCPlusPlus {
    fisher_matrices: HashMap<String, Matrix>,
    optimal_weights: HashMap<String, Tensor>,
    lambda: f32,        // Regularization strength (default: 2000)
    gamma: f32,         // Online EWC decay (default: 0.95)
}

impl EWCPlusPlus {
    /// Compute Fisher Information Matrix
    pub fn compute_fisher(&self, model: &Model, data: &DataLoader) -> HashMap<String, Matrix> {
        let mut fisher = HashMap::new();

        for batch in data {
            let outputs = model.forward(&batch.inputs);
            let log_probs = outputs.log_softmax(-1);

            // Sample from model's own distribution
            let samples = log_probs.multinomial(1);
            let loss = log_probs.gather(-1, &samples).mean();

            // Accumulate squared gradients
            let grads = loss.backward();
            for (name, grad) in grads {
                fisher.entry(name.clone())
                    .or_insert_with(|| Matrix::zeros_like(&grad))
                    .add_scaled(&grad.pow(2), 1.0 / data.len() as f32);
            }
        }

        fisher
    }

    /// EWC++ loss with online Fisher updates
    pub fn ewc_loss(&self, model: &Model) -> f32 {
        let mut loss = 0.0;

        for (name, param) in model.named_parameters() {
            if let (Some(fisher), Some(optimal)) =
                (self.fisher_matrices.get(name), self.optimal_weights.get(name))
            {
                // Quadratic penalty: lambda/2 * F * (theta - theta*)^2
                let diff = param - optimal;
                loss += (self.lambda / 2.0) * (fisher * diff.pow(2)).sum();
            }
        }

        loss
    }

    /// Online update of Fisher matrix (EWC++ improvement)
    pub fn update_fisher_online(&mut self, new_fisher: HashMap<String, Matrix>) {
        for (name, new_f) in new_fisher {
            self.fisher_matrices
                .entry(name)
                .and_modify(|f| {
                    // Exponential moving average
                    *f = f.scale(self.gamma) + new_f.scale(1.0 - self.gamma);
                })
                .or_insert(new_f);
        }
    }
}
```

**EWC++ Hyperparameters:**

| Parameter | Recommended Value | Description |
|-----------|-------------------|-------------|
| lambda (λ) | 2000 | Regularization strength |
| gamma (γ) | 0.95 | Online Fisher decay |
| Fisher samples | 1000+ | Samples for FIM estimation |

